import { Component, computed, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { ActivatedRoute, RouterLink } from '@angular/router';
import { toSignal } from '@angular/core/rxjs-interop';
import { map } from 'rxjs/operators';
import { MoneyPipe } from '../../core/pipes/money.pipe';
import { CartService } from '../../core/services/cart.service';
import { Product } from '../../core/models/storefront.models';

@Component({
  selector: 'app-catalog-detail',
  standalone: true,
  imports: [CommonModule, RouterLink, MoneyPipe],
  templateUrl: './catalog-detail.component.html',
})
export class CatalogDetailComponent {
  private routeId = toSignal(this.route.paramMap.pipe(map((p) => p.get('id'))), {
    initialValue: null,
  });

  added = signal(false);

  products = signal<Product[]>([
    {
      id: 'p1',
      name: 'Aurora Wireless Headphones',
      description:
        'Over-ear noise-cancelling headphones with 30-hour battery life, plush memory-foam ear cups, and multipoint Bluetooth. Includes a hard travel case and USB-C fast charging.',
      priceCents: 14999,
      imageUrl: 'https://picsum.photos/seed/headphones/720/540',
      stockQty: 12,
    },
    {
      id: 'p2',
      name: 'Nimbus Mechanical Keyboard',
      description:
        'Hot-swappable 75% mechanical keyboard with tactile brown switches, PBT double-shot keycaps, and per-key RGB. Wireless and wired modes supported.',
      priceCents: 9900,
      imageUrl: 'https://picsum.photos/seed/keyboard/720/540',
      stockQty: 34,
    },
    {
      id: 'p3',
      name: 'Vertex 4K Webcam',
      description:
        'Ultra-sharp 4K webcam with AI auto-framing, low-light correction, and a dual-microphone array. Clamps to any monitor or tripod.',
      priceCents: 7999,
      imageUrl: 'https://picsum.photos/seed/webcam/720/540',
      stockQty: 8,
    },
    {
      id: 'p4',
      name: 'Terra Standing Desk Mat',
      description:
        'Ergonomic anti-fatigue mat with contoured comfort zones and a durable non-slip base. Designed for long standing sessions.',
      priceCents: 5499,
      imageUrl: 'https://picsum.photos/seed/deskmat/720/540',
      stockQty: 20,
    },
    {
      id: 'p5',
      name: 'Lumen Desk Lamp',
      description:
        'Dimmable LED desk lamp with a 10W wireless charging base, USB-C passthrough, and five color temperatures. Touch controls with memory.',
      priceCents: 6299,
      imageUrl: 'https://picsum.photos/seed/lamp/720/540',
      stockQty: 15,
    },
    {
      id: 'p6',
      name: 'Cobalt Travel Backpack',
      description:
        'Water-resistant 22L travel backpack with a padded 16" laptop sleeve, hidden security pocket, and luggage pass-through strap.',
      priceCents: 11999,
      imageUrl: 'https://picsum.photos/seed/backpack/720/540',
      stockQty: 0,
    },
  ]);

  product = computed<Product | undefined>(() =>
    this.products().find((p) => p.id === this.routeId()),
  );

  constructor(
    private route: ActivatedRoute,
    private cart: CartService,
  ) {}

  addToCart(): void {
    const p = this.product();
    if (!p || p.stockQty <= 0) return;
    this.cart.count.update((n) => n + 1);
    this.added.set(true);
    setTimeout(() => this.added.set(false), 1500);
  }
}
